1	/** A live cell identified by its [x, y] coordinates. */
2	type Cell = [number, number];
3	
4	/** Encodes a cell as a string so it can be used as a Set/Map key. */
5	const toKey = ([x, y]: Cell): string => `${x},${y}`;
6	
7	/** Decodes a string key back into a cell. */
8	const fromKey = (key: string): Cell => {
9	  const [x, y] = key.split(",").map(Number);
10	  return [x, y];
11	};
12	
13	/** The eight offsets from a cell to each of its surrounding neighbors. */
14	const NEIGHBOR_OFFSETS: Cell[] = [
15	  [-1, -1], [0, -1], [1, -1],
16	  [-1, 0], [1, 0],
17	  [-1, 1], [0, 1], [1, 1],
18	];
19	
20	/** The eight cells immediately surrounding the given cell. */
21	const neighborsOf = ([x, y]: Cell): Cell[] =>
22	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
23	
24	/**
25	 * Conway's transition rule: a cell is live next generation when it has
26	 * exactly 3 live neighbors (birth), or it is currently alive and has
27	 * exactly 2 live neighbors (survival).
28	 */
29	const willLive = (isAlive: boolean, liveNeighbors: number): boolean =>
30	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
31	
32	export function nextGeneration(cells: Cell[]): Cell[] {
33	  const living = new Set(cells.map(toKey));
34	
35	  const neighborCounts = new Map<string, number>();
36	  for (const cell of cells) {
37	    for (const neighbor of neighborsOf(cell)) {
38	      const key = toKey(neighbor);
39	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
40	    }
41	  }
42	
43	  return [...neighborCounts]
44	    .filter(([key, liveNeighbors]) => willLive(living.has(key), liveNeighbors))
45	    .map(([key]) => fromKey(key));
46	}
