1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("returns an empty array for an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 underpopulation: two cells each with 1 neighbor die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 4 reproduction: a dead cell with exactly 3 live neighbors becomes alive", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(
18	      expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]),
19	    );
20	  });
21	  it("Rule 2 survival: a live cell with 2 live neighbors lives on", () => {
22	    // Three in a row: only the middle cell has 2 live neighbors and survives.
23	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
24	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
25	    expect(result).toContainEqual([1, 0]);
26	  });
27	  it("Rule 3 overpopulation: a live cell with more than 3 live neighbors dies", () => {
28	    // ### / .#. / ### — the center (1,1) has 6 live neighbors → dies.
29	    const result = nextGeneration([
30	      [0, 0], [1, 0], [2, 0],
31	      [1, 1],
32	      [0, 2], [1, 2], [2, 2],
33	    ]);
34	    expect(result).not.toContainEqual([1, 1]);
35	  });
36	  it("Block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
37	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
38	    const result = nextGeneration(block);
39	    expect(result).toHaveLength(4);
40	    expect(result).toEqual(expect.arrayContaining(block));
41	  });
42	  it("Blinker oscillator: vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
43	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
44	    expect(result).toHaveLength(3);
45	    expect(result).toEqual(
46	      expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]),
47	    );
48	  });
49	  it.todo("handles negative coordinates");
50	});
